function processCSVWithLogging(csvData) {
  const result = parseCSV(csvData);

  // Log summary
  console.log(`Processed CSV: ${result.rows.length} valid rows, ${result.errors.length} errors`);

  // Log errors for investigation
  if (result.errors.length > 0) {
    console.log("\nProblematic rows:");
    result.errors.forEach(error => {
      console.log(`  Row ${error.row}: ${error.message}`);
    });
  }

  // Return results for further processing
  return {
    data: result.rows,
    headers: result.headers,
    hasErrors: result.errors.length > 0,
    errorCount: result.errors.length,
    successRate: (result.rows.length / (result.rows.length + result.errors.length) * 100).toFixed(1) + '%'
