/**
 * CSV Parser Library (JavaScript version)
 * Comprehensive CSV parsing with type coercion, error handling, and aggregation
 */

/**
 * Coerces a string value to its appropriate type (number, boolean, null, or string)
 */
function coerceValue(value) {
  // Handle null
  if (value === "" || value.toLowerCase() === "null") {
    return null;
  }

  // Handle booleans
  if (value.toLowerCase() === "true") {
    return true;
  }
  if (value.toLowerCase() === "false") {
    return false;
  }

  // Handle numbers
  const num = Number(value);
  if (!isNaN(num) && value.trim() !== "") {
    return num;
  }

  // Default to string
  return value;
}

/**
 * Parses a CSV string into fields, handling quoted fields and delimiters
 */
function parseFields(line, delimiter, quote) {
  const fields = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];

    if (char === quote) {
      if (inQuotes && line[i + 1] === quote) {
        // Escaped quote (two quotes in a row)
        current += quote;
        i += 2;
      } else {
        // Toggle quote state
        inQuotes = !inQuotes;
        i++;
      }
    } else if (char === delimiter && !inQuotes) {
      // Delimiter outside quotes - end of field
      fields.push(current);
      current = "";
      i++;
    } else {
      current += char;
      i++;
    }
  }

  // Add the last field
  fields.push(current);

  return fields;
}

/**
 * Result object returned by parseCSV
 */
class CSVResult {
  constructor(rows, headers, errors) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  /**
   * Filter rows based on a predicate function
   */
  filter(predicate) {
    const filtered = this.rows.filter(predicate);
    return new CSVResult(filtered, this.headers, this.errors);
  }

  /**
   * Sum numeric values in a column
   */
  sum(column) {
    return this.rows.reduce((acc, row) => {
      const value = row[column];
      const num = typeof value === "number" ? value : 0;
      return acc + num;
    }, 0);
  }

  /**
   * Calculate average of numeric values in a column
   */
  average(column) {
    const count = this.rows.length;
    if (count === 0) return 0;
    return this.sum(column) / count;
  }

  /**
   * Count total rows
   */
  count() {
    return this.rows.length;
  }

  /**
   * Group rows by a column's values
   */
  groupBy(column) {
    const groups = new Map();

    for (const row of this.rows) {
      const key = row[column];
      if (!groups.has(key)) {
        groups.set(key, []);
      }
      groups.get(key).push(row);
    }

    return groups;
  }
}

/**
 * Main CSV parser function
 */
function parseCSV(input, options) {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator ?? "\n";

  const errors = [];

  // Handle empty input
  if (!input || input.trim() === "") {
    return new CSVResult([], [], []);
  }

  // Split into lines
  const lines = input.split(lineSeparator);

  // Filter out empty lines at the end
  let contentLines = lines;
  while (contentLines.length > 0 && contentLines[contentLines.length - 1].trim() === "") {
    contentLines.pop();
  }

  if (contentLines.length === 0) {
    return new CSVResult([], [], []);
  }

  // Parse headers
  const headerFields = parseFields(contentLines[0], delimiter, quote);
  const headers = headerFields.map((h) => h.trim());

  // Parse data rows
  const rows = [];

  for (let i = 1; i < contentLines.length; i++) {
    try {
      const fields = parseFields(contentLines[i], delimiter, quote);

      // Check if row has correct number of fields
      if (fields.length !== headers.length) {
        errors.push({
          row: i + 1,
          message: `Row has ${fields.length} fields, expected ${headers.length}`,
        });
        continue;
      }

      // Create row object with type coercion
      const row = {};
      for (let j = 0; j < headers.length; j++) {
        const value = fields[j].trim();
        row[headers[j]] = coerceValue(value);
      }

      rows.push(row);
    } catch (err) {
      errors.push({
        row: i + 1,
        message: `Error parsing row: ${err instanceof Error ? err.message : String(err)}`,
      });
    }
  }

  return new CSVResult(rows, headers, errors);
}

module.exports = { parseCSV, CSVResult };

