4,Diana Prince,diana@example.com,31,active
5,Eve Wilson,eve@domain.com,26,active`;

const result = parseCSV(customerCSV);

// Remove records with invalid data
const cleaned = result.filter(row => 
  // Must have email
  row.email && row.email.includes('@') &&
  // Must have valid age (number between 18 and 120)
  typeof row.age === 'number' && row.age >= 18 && row.age <= 120 &&
  // Must be active
  row.status === 'active'
);

console.log(`Original records: ${result.count()}`);
console.log(`Cleaned records: ${cleaned.count()}`);
// Original records: 5
// Cleaned records: 3

console.log("Valid customers:");
cleaned.rows.forEach(row => {
  console.log(`- ${row.name} (${row.email})`);
});
// Valid customers:
// - Alice Johnson (alice@example.com)
// - Diana Prince (diana@example.com)
// - Eve Wilson (eve@domain.com)
