## Real-World Scenario: E-Commerce Inventory Report

```typescript
const inventoryCSV = `sku,product_name,category,price,quantity,reorder_point,supplier,lead_time_days
SKU001,Widget A,Hardware,29.99,150,50,Supplier A,7
SKU002,Widget B,Hardware,19.99,25,50,Supplier B,14
SKU003,Gadget X,Electronics,99.99,5,20,Supplier A,10
SKU004,Gadget Y,Electronics,79.99,100,50,Supplier C,5
SKU005,Service Plan,Service,149.99,null,0,Internal,0`;

const result = parseCSV(inventoryCSV);

console.log("=== INVENTORY REPORT ===\n");

// 1. Low Stock Alert
console.log("LOW STOCK ALERT:");
const lowStock = result.filter(row => 
  typeof row.quantity === 'number' && row.quantity < row.reorder_point
);

if (lowStock.count() > 0) {
  lowStock.rows.forEach(row => {
    const shortfall = row.reorder_point - row.quantity;
    console.log(`  ${row.product_name}: ${row.quantity} units (need ${shortfall} more)`);
  });
} else {
  console.log("  All items adequately stocked");
}

// 2. Inventory Value
console.log("\nINVENTORY VALUE BY CATEGORY:");
const byCategory = result.groupBy("category");
let totalValue = 0;

for (const [category, items] of byCategory) {
  const value = items.reduce((sum, item) => {
    const qty = typeof item.quantity === 'number' ? item.quantity : 0;
    return sum + (item.price * qty);
  }, 0);
  totalValue += value;
  console.log(`  ${category}: $${value.toFixed(2)}`);
}

console.log(`  TOTAL: $${totalValue.toFixed(2)}`);

// 3. Supplier Analysis
console.log("\nSUPPLIER REORDER STATUS:");
const bySupplier = result.groupBy("supplier");

for (const [supplier, items] of bySupplier) {
  if (supplier === "Internal") continue;

  const needsReorder = items.filter(item => 
    typeof item.quantity === 'number' && item.quantity < item.reorder_point
  );

  if (needsReorder.length > 0) {
    console.log(`  ${supplier}:`);
    needsReorder.forEach(item => {
      console.log(`    - ${item.product_name} (${item.lead_time_days} day lead time)`);
    });
  }
}
```

This example demonstrates a realistic use case combining multiple features of the CSV parser.

